var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"난 무능해...... 초등학생보다도 재능이 없어......","JPN":"私は無能だ……初等部よりも才能のない……","ENG":"I'm incompetent... Less talented than an elementary school kid...","TWN":"我很無能……連小學生都不如……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"나 같이 무능한 건 차라리 태어나지 않는 편이 나았어.","JPN":"私みたいな無能は生まれてこなければよかった。","ENG":"An incompetent like me should have never been born.","TWN":"像我這麼無能的人不應該出生的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이대로...... 모두의 기억에서 잊혀져 버리고 싶어......","JPN":"このまま……みんなの記憶から忘れられてしまいたい……","ENG":"I... I want to be forgotten from everyone's memories...","TWN":"我想……就這樣被大家遺忘……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그런 말은 하지 마!","JPN":"そんなこと言わないで！","ENG":"Don't say that!","TWN":"別再說那種話！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"뭐...... 라고? 거기 누구야?!","JPN":"えっ……？　そこに誰かいるの！？","ENG":"What... What was that? Who's there?","TWN":"什……什麼？誰在那兒？！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"여기서 포기하면 안 돼!","JPN":"ここで諦めたらダメだよ！","ENG":"Don't give up now!","TWN":"不可以放棄！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"잊혀지고 싶다거나 그런 말은 하지 마!","JPN":"忘れられたいなんて、そんなことは言わないで！","ENG":"Don't ever say you want to be forgotten!","TWN":"不要再說想要被遺忘之類的話！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"주저앉지 마! 실패하더라도 끝까지 싸워야 돼!","JPN":"挫けないで！　失敗しても最後まで戦わないと！","ENG":"Don't quit! Even if you fail, try again and again—until the end!","TWN":"別氣餒！失敗了也要奮戰到最後！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"여기서 포기하면...... 정말로 사라져 버릴지도 몰라!","JPN":"ここで諦めたら……本当に消えてしまうかもしれない！","ENG":"If you give up now... you might really disappear!","TWN":"就此放棄的話……說不定真的會消失！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이건...... 어디서 들리는 목소리지?","JPN":"これは……どこから聞こえる声なの？","ENG":"This voice... Where is it coming from?","TWN":"這個……聲音是從哪兒傳來的？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"희미하지만...... 어째서인지 선명하게 들리고 있어.","JPN":"かすかだけど……なぜか鮮明に聞こえてくる。","ENG":"It's barely audible, but I can hear it clearly.","TWN":"雖然很輕……聽起來卻很清楚。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"크윽...... 여기까지인가......","JPN":"クッ…ここまでか……","ENG":"Ugh... Is this it?","TWN":"呃……只能到這裡了嗎……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"최면 마술은 아직 미완성의 비기.","JPN":"催眠術は未完成の秘技。","ENG":"My hypnosis magic isn't complete, not just yet.","TWN":"這個催眠魔術是還沒完成的秘技。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"나의 육체가...... 정신을 따라오지 못하는군.","JPN":"俺の肉体が……精神について来れない。","ENG":"My body can't keep up with my mind.","TWN":"我的身體……跟不上催眠後的精神力了。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_DODGE","text":{"KOREA":"지금이다! 미카가 많이 지친 것 같아!","JPN":"今だ！　ミカが疲れてきたみたいだ！","ENG":"Now is our chance! Mika is exhausted!","TWN":"就是現在！米卡好像不行了！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_DODGE","text":{"KOREA":"......그러니까, 저게 미카가 맞는지는 모르겠지만.","JPN":"……だから、あれがミカなのかはわからないけど。","ENG":"I mean, if that's really Mika.","TWN":"……雖然不知道那個是不是米卡。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_DODGE","text":{"KOREA":"일단 그런 건 나중에 생각하자! 다들 집중 공격해!","JPN":"とりあえずそんなことは後で考えよう！　全員、集中攻撃！","ENG":"We'll figure that out later. Everyone, focus on her!","TWN":"那個等以後再想吧！大家先集中進攻！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};